object SecureXMLParser {
  def createSecureParser(): XMLLoader[Elem] = {
    new XMLLoader[Elem] {
      override def parser: SAXParser = {
        val factory = SAXParserFactory.newInstance()
        factory.setNamespaceAware(false)
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false)
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false)
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true)
        factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false)
        factory.setXIncludeAware(false)
        factory.newSAXParser()
      }
      
      def load(is: InputSource): Elem = {
        loadXML(is, parser)
      }
    }
  }
  
  def parseSecurely(xmlString: String): Elem = {
    val loader = createSecureParser()
    val inputSource = new InputSource(new StringReader(xmlString))
    loader.load(inputSource)
  }
}

class ConfigurationService {
  
  def parseConfiguration(xmlString: String): Either[String, ConfigurationSettings] = {
    try {
      val xml = SecureXMLParser.parseSecurely(xmlString)
      Right(extractSettings(xml))
    } catch {
      case e: Exception => Left(s"Failed to parse XML: ${e.getMessage}")
    }
  }
  
  private def extractSettings(node: Node): ConfigurationSettings = {
    val settings = (node \ "setting").map { setting =>
      val key = (setting \ "@key").text
      val value = (setting \ "@value").text
      key -> value
    }.toMap
    
    val nestedConfigs = (node \ "config").map { config =>
      val name = (config \ "@name").text
      name -> extractSettings(config)
    }.toMap
    
    ConfigurationSettings(settings, nestedConfigs)
  }
  
  def getSetting(config: ConfigurationSettings, key: String): Option[String] = {
    config.settings.get(key)
  }
  
  def getNestedConfig(config: ConfigurationSettings, name: String): Option[ConfigurationSettings] = {
    config.nestedConfigs.get(name)
  }
  
  def getAllSettings(config: ConfigurationSettings): Map[String, String] = {
    config.settings
  }
  
  def flattenSettings(config: ConfigurationSettings, prefix: String = ""): Map[String, String] = {
    val currentSettings = if (prefix.isEmpty) {
      config.settings
    } else {
      config.settings.map { case (k, v) => s"$prefix.$k" -> v }
    }
    
    val nestedSettings = config.nestedConfigs.flatMap { case (name, nestedConfig) =>
      val newPrefix = if (prefix.isEmpty) name else s"$prefix.$name"
      flattenSettings(nestedConfig, newPrefix)
    }
    
    currentSettings ++ nestedSettings
  }
}

class ConfigurationAPI {
  private val configService = new ConfigurationService()
  
  def handleConfigurationRequest(xmlPayload: String): Either[String, Map[String, String]] = {
    configService.parseConfiguration(xmlPayload) match {
      case Right(config) => Right(configService.flattenSettings(config))
      case Left(error) => Left(error)
    }
  }
  
  def extractSpecificSetting(xmlPayload: String, settingKey: String): Either[String, String] = {
    configService.parseConfiguration(xmlPayload) match {
      case Right(config) => 
        configService.getSetting(config, settingKey)
          .toRight(s"Setting '$settingKey' not found")
      case Left(error) => Left(error)
    }
  }
  
  def extractNestedConfiguration(xmlPayload: String, configName: String): Either[String, Map[String, String]] = {
    configService.parseConfiguration(xmlPayload) match {
      case Right(config) =>
        configService.getNestedConfig(config, configName)
          .map(nested => configService.flattenSettings(nested))
          .toRight(s"Nested configuration '$configName' not found")
      case Left(error) => Left(error)
    }
  }
  
  def validateAndParseConfiguration(xmlPayload: String): Either[String, ConfigurationSettings] = {
    if (xmlPayload == null || xmlPayload.trim.isEmpty) {
      Left("XML payload cannot be empty")
    } else if (xmlPayload.length > 1048576) {
      Left("XML payload exceeds maximum size limit")
    } else {
      configService.parseConfiguration(xmlPayload)
    }
  }
}

